#include <stdio.h>
#include <limits.h>

int main(void){
	long long int m, b;
	scanf("%lld%lld", &m, &b);
	long long int i;
	long long int max = INT_MIN;
	for(i=b; i>=0; i--){
		long long int x = (b-i)*m;
		long long int w = x*(x+1)/2;
		long long int p = i*(i+1)/2;
		long long int val = w*(i+1)+p*(x+1);
		if(val > max){
			max = val;
		}
	}
	printf("%lld\n", max);
	return 0;
}

